interface.signature:
async executeWithRetry<T>(
  operation: () => Promise<T>,
  options?: RetryOptions
): Promise<T>

interface RetryOptions {
  maxAttempts?: number;      // Default: 3
  baseDelay?: number;         // Default: 1000ms
  context?: string;           // For logging
  onRetry?: (attempt: number, error: Error) => void;
}

async send(message: admin.messaging.Message): Promise<string>

// Message interface includes:
// - token: string (device token)
// - notification: { title: string, body: string }
// - data?: Record<string, string>
// - apns, android: platform-specific configs

get<T = any>(propertyPath: string, defaultValue?: T): T

// Usage:
// this.configService.get<number>('FIREBASE_RETRY_MAX_ATTEMPTS', 5)
// this.configService.get<number>('FIREBASE_RETRY_BASE_DELAY', 2000)

// Firebase messaging error codes:
// - messaging/invalid-registration-token: Invalid device token (don't retry)
// - messaging/invalid-argument: Invalid message format (don't retry)
// - messaging/unavailable: Service unavailable (retry)
// - messaging/server-error: Server error (retry)
// - messaging/quota-exceeded: Quota exceeded (retry with backoff)

// Error object structure:
// error.code: string (error code)
// error.message: string (error message)
